mapper.select:
SELECT 
FROM pinova.member_shipping_address
WHERE id = #{addressId}
  AND member_id = #{memberId}
  AND deleted = false
FOR UPDATE

mapper.update:
UPDATE pinova.member_shipping_address
SET is_default = false,
    version = version + 1,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = #{operatorId}
WHERE member_id = #{memberId}
  AND is_default = true
  AND deleted = false

  AND id <> #{excludedAddressId}

UPDATE pinova.member_shipping_address
SET is_default = true,
    version = version + 1,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = #{operatorId}
WHERE id = #{addressId}
  AND member_id = #{memberId}
  AND version = #{version}
  AND deleted = false

UPDATE pinova.member_shipping_address
SET is_default = false,
    deleted = true,
    deleted_at = CURRENT_TIMESTAMP,
    deleted_by = #{operatorId},
    version = version + 1,
    updated_at = CURRENT_TIMESTAMP,
    updated_by = #{operatorId}
WHERE id = #{addressId}
  AND member_id = #{memberId}
  AND version = #{version}
  AND deleted = false
